import { Command } from '@tauri-apps/plugin-shell';

async function dockerComposeUp(composeFile: string): Promise<{ code: number; stdout: string; stderr: string }> {
  const command = Command.create('docker-compose-up', [composeFile]);
  const output = await command.execute();
  return { code: output.code, stdout: output.stdout, stderr: output.stderr };
}

