import { Command } from '@tauri-apps/plugin-shell';

async function streamDockerLogs(composeFile: string, onLine: (line: string) => void): Promise<void> {
  const command = Command.create('docker-compose-logs', [composeFile, '100']);
  command.stdout.on('data', (line: string) => onLine(line));
  command.stderr.on('data', (line: string) => onLine(`[stderr] ${line}`));
  command.on('error', (error: string) => console.error('Process error:', error));
  command.on('close', (data) => console.log('Process exited with code', data.code));
  await command.spawn();
}

